public static void main(String[] args) {
    float[][] matrix = new float[4][4];

    // initialize values of the 2D array
    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 4; j++) {
            matrix[i][j] = i + j;
        }
    }

    Matrix4f m4f = new Matrix4f(matrix);
    float[] linearData = m4f.getLinearData();

    // print the values in the linear array
    for (int i = 0; i < linearData.length; i++) {
        System.out.println("Linear data[" + i + "]: " + linearData[i]);
    }
}

public class Matrix {
    private float[][] data;
    public Matrix(float[][] data) { this.data = data; }
    public float get(int x, int y) { return data[x][y]; }
}

public class Main {
    public static void main(String[] args) {
        // Create a 2x3 matrix with the given values
        float[][] data = new float[][] {
            {1.0f, 2.0f, 3.0f},
            {4.0f, 5.0f, 6.0f}
        };
        Matrix matrix = new Matrix(data);

        // Print the value at the 1st column and 2nd row
        System.out.println(matrix.get(1, 2)); // Output: 6.0
    }
}

